export interface AlertStylesType {
  defaultProps?: {
    variant?: variant;
    color?: color;
    icon?: icon;
    open?: open;
    action?: action;
    onClose?: onClose;
    animate?: animate;
    className?: className;
  };
  valid?: {
    variants?: string[];
    colors?: string[];
  };
  styles?: {
    base?: {
      alert?: object;
      action?: object;
    };
    variants?: {
      filled?: typeof alertFilled;
      gradient?: typeof alertGradient;
      outlined?: typeof alertOutlined;
      ghost?: typeof alertGhost;
    };
  };
}

