"use client";

import React from "react";

import {cn} from "@/utils/cn";

interface HorizontalScrollingBannerProps {
  children: React.ReactNode;
  className?: string;
  duration?: number; // in seconds
  gap?: string;
  isReverse?: boolean;
  shouldPauseOnHover?: boolean;
  showShadow?: boolean;
  shadowSize?: string;
}

const HorizontalScrollingBanner = React.forwardRef<HTMLDivElement, HorizontalScrollingBannerProps>(
  (
    {
      children,
      className,
      duration = 40,
      gap = "1rem",
      isReverse = false,
      shadowSize = "60px",
      shouldPauseOnHover = true,
      showShadow = true,
    },
    ref,
  ) => {
    const maskImage = showShadow
      ? `linear-gradient(to right, transparent, #000 ${shadowSize}, #000 calc(100% - ${shadowSize}), transparent)`
      : undefined;

    return (
      <div
        ref={ref}
        className={cn("flex w-full overflow-x-hidden", className)}
        style={
          {
            "--duration": `${duration}s`,
            "--gap": gap,
            WebkitMaskImage: maskImage,
            maskImage,
          } as React.CSSProperties
        }
      >
        <div
          className="flex w-max items-stretch"
          style={{
            animation: `scrolling-banner var(--duration) linear infinite`,
            animationDirection: isReverse ? "reverse" : "normal",
            gap: `var(--gap)`,
          }}
          onMouseEnter={(e) => {
            if (shouldPauseOnHover) {
              e.currentTarget.style.animationPlayState = "paused";
            }
          }}
          onMouseLeave={(e) => {
            if (shouldPauseOnHover) {
              e.currentTarget.style.animationPlayState = "running";
            }
          }}
        >
          {/* Clone children and duplicate for seamless loop */}
          {React.Children.map(children, (child, index) => (
            <div key={`original-${index}`} className="shrink-0">
              {React.cloneElement(child as React.ReactElement)}
            </div>
          ))}
          {React.Children.map(children, (child, index) => (
            <div key={`duplicate-${index}`} className="shrink-0">
              {React.cloneElement(child as React.ReactElement)}
            </div>
          ))}
        </div>
      </div>
    );
  },
);

HorizontalScrollingBanner.displayName = "HorizontalScrollingBanner";

export default HorizontalScrollingBanner;

"use client";

import type {CodeBlockProps} from "fumadocs-ui/components/codeblock";
import type {ComponentProps, RefObject} from "react";

import {buttonVariants} from "@heroui/react";
import {CodeBlock} from "fumadocs-ui/components/codeblock";
import {useCopyButton} from "fumadocs-ui/utils/use-copy-button";
import {useRef} from "react";

import {Iconify} from "@/components/iconify";
import {cn} from "@/utils/cn";

export function FumadocsCustomCodeblock({
  allowCopy = true,
  children,
  code,
  ...props
}: {children: React.ReactNode; code?: string} & CodeBlockProps) {
  const areaRef = useRef<HTMLDivElement>(null);

  return (
    <CodeBlock
      {...props}
      allowCopy={allowCopy}
      // @ts-expect-error - TODO: fumadocs-ui error
      viewportProps={{ref: areaRef}}
      Actions={(actionsProps) => (
        <div {...actionsProps} className={cn("z-1! empty:hidden", actionsProps.className)}>
          {!!allowCopy && <CopyButton code={code} containerRef={areaRef} />}
        </div>
      )}
    >
      {children}
    </CodeBlock>
  );
}

function CopyButton({
  className,
  code,
  containerRef,
  ...props
}: ComponentProps<"button"> & {
  code?: string;
  containerRef: RefObject<HTMLElement | null>;
}) {
  const [checked, onClick] = useCopyButton(() => {
    if (code) {
      void navigator.clipboard.writeText(code);

      return;
    }

    const pre = containerRef.current?.getElementsByTagName("pre").item(0);

    if (!pre) return;

    const clone = pre.cloneNode(true) as HTMLElement;

    clone.querySelectorAll(".nd-copy-ignore").forEach((node) => {
      node.replaceWith("\n");
    });

    void navigator.clipboard.writeText(clone.textContent ?? "");
  });

  return (
    <button
      aria-label={checked ? "Copied Text" : "Copy Text"}
      data-checked={checked || undefined}
      type="button"
      className={buttonVariants({
        class: cn("-mt-0.5 bg-transparent text-muted", className),
        isIconOnly: true,
        size: "sm",
        variant: "ghost",
      })}
      onClick={onClick}
      {...props}
    >
      {checked ? <Iconify icon="check" /> : <Iconify icon="copy" />}
    </button>
  );
}
